  1→package connector
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→	"io"
  8→	"net/http"
  9→	"os"
 10→	"strings"
 11→
 12→	"golang.org/x/oauth2"
 13→	"golang.org/x/oauth2/google"
 14→)
 15→
 16→// GenericConnector implements Connector backed by a YAMLConnector definition.
 17→type GenericConnector struct {
 18→	def         *YAMLConnector
 19→	credentials string // optional override path (e.g. --credentials flag)
 20→}
 21→
 22→// saveToken writes an OAuth2 token to disk with restricted permissions.
 23→func saveToken(path string, token *oauth2.Token) error {
 24→	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
 25→	if err != nil {
 26→		return err
 27→	}
 28→	defer f.Close()
 29→	return json.NewEncoder(f).Encode(token)
 30→}
 31→
 32→func (g *GenericConnector) ID() string   { return g.def.ID }
 33→func (g *GenericConnector) Name() string { return g.def.Name }
 34→func (g *GenericConnector) Type() string { return g.def.Type }
 35→
 36→func (g *GenericConnector) Connect(ctx context.Context) (*Result, error) {
 37→	switch g.def.Auth.Method {
 38→	case "oauth2":
 39→		return g.connectOAuth2(ctx)
 40→	case "api_key":
 41→		return g.connectAPIKey(ctx)
 42→	case "basic":
 43→		return g.connectBasic(ctx)
 44→	case "webhook":
 45→		return g.connectWebhook(ctx)
 46→	default:
 47→		return nil, fmt.Errorf("unsupported auth method: %s", g.def.Auth.Method)
 48→	}
 49→}
 50→
 51→func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 52→	var oauthCfg *oauth2.Config
 53→	var authOpts []oauth2.AuthCodeOption
 54→
 55→	if g.def.Credentials.Source == "google_json" {
 56→		// Google-specific: use google.ConfigFromJSON
 57→		credsData, err := g.loadGoogleCredentials()
 58→		if err != nil {
 59→			return nil, err
 60→		}
 61→		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 62→		if err != nil {
 63→			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 64→		}
 65→		oauthCfg = cfg
 66→	} else {
 67→		// Generic OAuth2: build config from YAML
 68→		clientID, clientSecret, err := g.resolveOAuthCredentials()
 69→		if err != nil {
 70→			return nil, err
 71→		}
 72→		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 73→		if err != nil {
 74→			return nil, err
 75→		}
 76→		oauthCfg = cfg
 77→		authOpts = opts
 78→	}
 79→
 80→	// Add extra_params as auth options for google_json too
 81→	if g.def.Credentials.Source == "google_json" {
 82→		for k, v := range g.def.Auth.ExtraParams {
 83→			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 84→		}
 85→	}
 86→
 87→	// Run shared OAuth flow
 88→	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 89→	if err != nil {
 90→		return nil, err
 91→	}
 92→
 93→	// Save token
 94→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 95→	tokenPath := tokenDir + "/token.json"
 96→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
 97→		return nil, fmt.Errorf("creating connector dir: %w", err)
 98→	}
 99→	if err := saveToken(tokenPath, token); err != nil {
100→		return nil, fmt.Errorf("saving token: %w", err)
101→	}
102→
103→	// Verify connection + get account identifier
104→	account, err := g.runVerify(ctx, oauthCfg, token)
105→	if err != nil {
106→		// Non-fatal: connected but can't verify
107→		account = "connected (unverified)"
108→	}
109→
110→	return &Result{
111→		Account: account,
112→		Token:   token,
113→	}, nil
114→}
115→
116→func (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
117→	key := os.Getenv(g.def.Auth.EnvVar)
118→	if key == "" {
119→		// Check if stdin is a TTY for prompt
120→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
121→			fmt.Printf("Enter your %s API key: ", g.def.Name)
122→			fmt.Scanln(&key)
123→		}
124→		if key == "" {
125→			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
126→		}
127→	}
128→
129→	// Save API key
130→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
131→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
132→		return nil, fmt.Errorf("creating connector dir: %w", err)
133→	}
134→	credsPath := tokenDir + "/credentials.json"
135→	credsData, _ := json.Marshal(map[string]string{"api_key": key})
136→	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
137→		return nil, fmt.Errorf("saving credentials: %w", err)
138→	}
139→
140→	// Verify
141→	account, err := g.runVerifyAPIKey(ctx, key)
142→	if err != nil {
143→		account = "connected (unverified)"
144→	}
145→
146→	return &Result{
147→		Account: account,
148→		Meta:    map[string]string{"api_key": key},
149→	}, nil
150→}
151→
152→func (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
153→	username := os.Getenv(g.def.Auth.UsernameVar)
154→	password := os.Getenv(g.def.Auth.PasswordVar)
155→	if username == "" || password == "" {
156→		return nil, fmt.Errorf("%s credentials not found. Set %s and %s environment variables",
157→			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
158→	}
159→
160→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
161→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
162→		return nil, fmt.Errorf("creating connector dir: %w", err)
163→	}
164→	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
165→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
166→		return nil, fmt.Errorf("saving credentials: %w", err)
167→	}
168→
169→	return &Result{Account: username}, nil
170→}
171→
172→func (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
173→	webhookURL := os.Getenv(g.def.Auth.URLVar)
174→	if webhookURL == "" {
175→		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
176→			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
177→			fmt.Scanln(&webhookURL)
178→		}
179→		if webhookURL == "" {
180→			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
181→				g.def.Name, g.def.Auth.URLVar)
182→		}
183→	}
184→
185→	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
186→	if err := os.MkdirAll(tokenDir, 0755); err != nil {
187→		return nil, fmt.Errorf("creating connector dir: %w", err)
188→	}
189→	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
190→	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
191→		return nil, fmt.Errorf("saving credentials: %w", err)
192→	}
193→
194→	return &Result{Account: webhookURL}, nil
195→}
196→
197→// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
198→func (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
199→	cfg := &oauth2.Config{
200→		ClientID:     clientID,
201→		ClientSecret: clientSecret,
202→		Scopes:       g.def.Auth.Scopes,
203→		Endpoint: oauth2.Endpoint{
204→			AuthURL:  g.def.Auth.AuthorizeURL,
205→			TokenURL: g.def.Auth.TokenURL,
206→		},
207→	}
208→
209→	// Auth style
210→	switch g.def.Auth.AuthStyle {
211→	case "in_params":
212→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
213→	case "in_header":
214→		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
215→	}
216→
217→	// Extra params become AuthCodeOptions
218→	var opts []oauth2.AuthCodeOption
219→	for k, v := range g.def.Auth.ExtraParams {
220→		opts = append(opts, oauth2.SetAuthURLParam(k, v))
221→	}
222→
223→	return cfg, opts, nil
224→}
225→
226→// resolveOAuthCredentials reads client ID and secret from the configured source.
227→func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
228→	cred := g.def.Credentials
229→
230→	switch cred.Source {
231→	case "env":
232→		id := os.Getenv(cred.ClientIDVar)
233→		secret := os.Getenv(cred.ClientSecretVar)
234→		if id == "" || secret == "" {
235→			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
236→				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
237→		}
238→		return id, secret, nil
239→
240→	case "prompt":
241→		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
242→			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
243→		}
244→		var id, secret string
245→		fmt.Printf("Enter %s client ID: ", g.def.Name)
246→		fmt.Scanln(&id)
247→		fmt.Printf("Enter %s client secret: ", g.def.Name)
248→		fmt.Scanln(&secret)
249→		if id == "" || secret == "" {
250→			return "", "", fmt.Errorf("client ID and secret are required")
251→		}
252→		return id, secret, nil
253→
254→	default:
255→		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
256→	}
257→}
258→
259→// loadGoogleCredentials loads credentials for google_json source (fallback chain).
260→func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
261→	// 1. Explicit path from --credentials flag
262→	if g.credentials != "" {
263→		data, err := os.ReadFile(g.credentials)
264→		if err != nil {
265→			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
266→		}
267→		return data, nil
268→	}
269→
270→	// 2. Local file in project
271→	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
272→	if data, err := os.ReadFile(localPath); err == nil {
273→		return data, nil
274→	}
275→
276→	// 3. Bundled credentials
277→	if len(BundledCredentials) > 0 {
278→		return BundledCredentials, nil
279→	}
280→
281→	return nil, fmt.Errorf("no %s credentials found — provide a credentials.json file", g.def.Name)
282→}
283→
284→// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
285→func (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
286→	if g.def.Verify.URL == "" {
287→		return "connected", nil
288→	}
289→
290→	// Refresh token first so URL substitution uses a valid access token
291→	ts := cfg.TokenSource(ctx, token)
292→	freshToken, err := ts.Token()
293→	if err != nil {
294→		freshToken = token // fall back to original if refresh fails
295→	}
296→	client := oauth2.NewClient(ctx, ts)
297→	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)
298→
299→	method := g.def.Verify.Method
300→	if method == "" {
301→		method = "GET"
302→	}
303→
304→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
305→	if err != nil {
306→		return "", err
307→	}
308→	for k, v := range g.def.Verify.Headers {
309→		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
310→		req.Header.Set(k, v)
311→	}
312→
313→	resp, err := client.Do(req)
314→	if err != nil {
315→		return "", err
316→	}
317→	defer resp.Body.Close()
318→
319→	if resp.StatusCode != 200 {
320→		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
321→	}
322→
323→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
324→}
325→
326→// runVerifyAPIKey calls verify with an API key in the configured header.
327→func (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
328→	if g.def.Verify.URL == "" {
329→		return "connected", nil
330→	}
331→
332→	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
333→	method := g.def.Verify.Method
334→	if method == "" {
335→		method = "GET"
336→	}
337→
338→	req, err := http.NewRequestWithContext(ctx, method, url, nil)
339→	if err != nil {
340→		return "", err
341→	}
342→
343→	if g.def.Auth.Header != "" {
344→		req.Header.Set(g.def.Auth.Header, key)
345→	}
346→
347→	resp, err := http.DefaultClient.Do(req)
348→	if err != nil {
349→		return "", err
350→	}
351→	defer resp.Body.Close()
352→
353→	if resp.StatusCode != 200 {
354→		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
355→	}
356→
357→	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
358→}
359→
360→// extractAccountField reads the JSON response and tries fields in preference order.
361→func extractAccountField(body io.Reader, fields []string) (string, error) {
362→	if len(fields) == 0 {
363→		return "connected", nil
364→	}
365→
366→	var data map[string]interface{}
367→	if err := json.NewDecoder(body).Decode(&data); err != nil {
368→		return "", fmt.Errorf("parsing verify response: %w", err)
369→	}
370→
371→	for _, field := range fields {
372→		if v, ok := data[field]; ok && v != nil {
373→			return fmt.Sprintf("%v", v), nil
374→		}
375→	}
376→
377→	return "connected", nil
378→}
