 73→// ── HTTP Handlers ────────────────────────────────────────────────────
 74→
 75→/**
 76→ * POST /api/google-auth
 77→ * Receives a Google ID token, verifies it, creates/finds user, returns Nurge token.
 78→ */
 79→export const googleAuth = httpAction(async (ctx, request) => {
 80→  try {
 81→    const body = await request.json();
 82→    const idToken = body.id_token;
 83→    if (!idToken) {
 84→      return jsonResponse({ error: "Missing id_token" }, 400);
 85→    }
 86→
 87→    // Verify ID token with Google
 88→    const googleResp = await fetch(
 89→      `https://oauth2.googleapis.com/tokeninfo?id_token=${idToken}`
 90→    );
 91→    if (!googleResp.ok) {
 92→      return jsonResponse({ error: "Invalid Google ID token" }, 401);
 93→    }
 94→
 95→    const googleUser = await googleResp.json();
 96→    const email: string = googleUser.email;
 97→    const name: string = googleUser.name || email.split("@")[0];
 98→
 99→    if (!email) {
100→      return jsonResponse({ error: "No email in Google token" }, 400);

100→      return jsonResponse({ error: "No email in Google token" }, 400);
101→    }
102→
103→    // Find or create user
104→    const existing = await ctx.runQuery(internal.auth.findUserByEmail, { email });
105→    const token = generateToken();
106→
107→    if (existing) {
108→      await ctx.runMutation(internal.auth.updateUserToken, {
109→        userId: existing._id,
110→        token,
111→        name,
112→      });
113→    } else {
114→      await ctx.runMutation(internal.auth.createUser, {
115→        email,
116→        name,
117→        token,
118→      });
119→    }
120→
121→    return jsonResponse({ token, email, name });
122→  } catch (e: any) {
123→    return jsonResponse({ error: e.message || "Internal error" }, 500);
124→  }
125→});
126→
127→/**
128→ * POST /api/validate-token
129→ * Validates a Nurge session token.
130→ */
131→export const validateToken = httpAction(async (ctx, request) => {
132→  try {
133→    const body = await request.json();
134→    const token = body.token;
135→    if (!token) {
136→      return jsonResponse({ valid: false }, 400);
137→    }
138→
139→    const user = await ctx.runQuery(internal.auth.findUserByToken, { token });
140→
141→    if (!user) {
142→      return jsonResponse({ valid: false });
143→    }
144→
145→    return jsonResponse({
146→      valid: true,
147→      user: { email: user.email, name: user.name },
148→    });
149→  } catch {
150→    return jsonResponse({ valid: false }, 500);
151→  }
152→});
153→
154→/**
155→ * POST /api/revoke-token
156→ * Clears the user's session token.
157→ */
158→export const revokeToken = httpAction(async (ctx, request) => {
159→  try {
160→    const body = await request.json();
161→    const token = body.token;
162→    if (!token) {
163→      return jsonResponse({ error: "Missing token" }, 400);
164→    }
165→
166→    const user = await ctx.runQuery(internal.auth.findUserByToken, { token });
167→
168→    if (user) {
169→      await ctx.runMutation(internal.auth.clearUserToken, {
170→        userId: user._id,
171→      });
172→    }
173→
174→    return jsonResponse({ ok: true });
175→  } catch {
176→    return jsonResponse({ ok: true }); // Best effort
177→  }
178→});
