 12→	"github.com/usenurge/nurgesh/internal/sequence"
 13→)
 14→
 15→var (
 16→	sendTo          string
 17→	sendCc          string
 18→	sendSubject     string
 19→	sendBody        string
 20→	sendSequence    string
 21→	sendCampaign    string
 22→	sendTaskID      string
 23→	sendSendType    string
 24→	sendContactName string
 25→)
 26→
 27→var sendCmd = &cobra.Command{
 28→	Use:   "send",
 29→	Short: "Send an email via Unipile",
 30→	Long:  "Send an email through your connected email account via Convex + Unipile.",
 31→	RunE: func(cmd *cobra.Command, args []string) error {
 32→		if sendSequence != "" && sendTaskID != "" {
 33→			return fmt.Errorf("--sequence and --task-id cannot be used together")
 34→		}
 35→
 36→		// Load auth token
 37→		authFile, err := account.LoadAuth()
 38→		if err != nil || authFile.Token == "" {
 39→			return fmt.Errorf("not logged in. Run: nurge account login")
 40→		}
 41→
 42→		// If --task-id is provided, resolve draft content from local DB for defaults
 43→		if sendTaskID != "" {
 44→			d, err := db.Open()
 45→			if err != nil {
 46→				return fmt.Errorf("opening database: %w", err)
 47→			}
 48→			defer d.Close()
 49→
 50→			task, err := sequence.TaskByID(d, sendTaskID)
 51→			if err != nil {
 52→				return err
 53→			}
 54→			if sendTo == "" {
 55→				sendTo = task.ContactEmail
 56→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 57→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 58→			}
 59→			if sendSubject == "" || sendBody == "" {
 60→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 61→				if err != nil {
 62→					return err
 63→				}
 64→				if sendSubject == "" {
 65→					sendSubject = renderedSubject
 66→				}
 67→				if sendBody == "" {
 68→					sendBody = renderedBody
 69→				}
 70→			}
 71→		}
 72→
 73→		if sendTo == "" {
 74→			return fmt.Errorf("recipient (--to) is required")
 75→		}
 76→		if sendSubject == "" {
 77→			return fmt.Errorf("subject (--subject) is required")
 78→		}
 79→		if sendBody == "" {
 80→			return fmt.Errorf("body (--body) is required")
 81→		}
 82→
 83→		// Build request
 84→		req := account.SendEmailRequest{
 85→			To:       strings.TrimSpace(sendTo),
 86→			Cc:       strings.TrimSpace(sendCc),
 87→			Subject:  sendSubject,
 88→			Body:     sendBody,
 89→			SendType: sequence.NormalizeSendType(sendSendType),
 90→			Sync:     true, // CLI-initiated sends are always sync
 91→			TaskID:   sendTaskID,
 92→		}
 93→
 94→		// Sequence enrollment
 95→		if sendSequence != "" {
 96→			req.SendType = sequence.SendTypeFirstTouch
 97→
 98→			d, err := db.Open()
 99→			if err != nil {
100→				return fmt.Errorf("opening database: %w", err)
101→			}
102→			defer d.Close()
103→
104→			seqReq := &account.SequenceRequest{
105→				SequenceName: sendSequence,
106→				CampaignName: sendCampaign,
107→				ContactName:  sendContactName,
108→			}
109→
110→			// Best-effort mailbox resolution for Convex
111→			if sendCampaign != "" {
112→				if campaign, cErr := sequence.CampaignByName(d, sendCampaign); cErr == nil {
113→					if mbx, mErr := sequence.CampaignMailbox(d, campaign); mErr == nil && mbx != nil {
114→						seqReq.MailboxID = mbx.ID
115→					}
116→				}
117→			}
118→
119→			// Get steps from built-in template
120→			tmpl, tmplErr := sequence.TemplateByName(d, sendSequence)
121→			if tmplErr == nil {
122→				for _, step := range tmpl.Steps {
123→					if step.StepNumber <= 1 {
124→						continue // skip first touch, that's the current send
125→					}
126→					seqReq.Steps = append(seqReq.Steps, account.SequenceStep{
127→						StepNumber: step.StepNumber,
128→						StepName:   step.Name,
129→						SendType:   step.SendType,
130→						DelayDays:  parseDays(step.Delay),
131→					})
132→				}
133→			}
134→
135→			req.Sequence = seqReq
136→		}
137→
138→		// Call Convex
139→		client := account.NewConvexClient(GetConvexURL())
140→		resp, err := client.SendEmail(authFile.Token, req)
141→		if err != nil {
142→			return fmt.Errorf("send failed: %w", err)
143→		}
144→
145→		if resp.Queued {
146→			fmt.Printf("  \033[33m⏳\033[0m Queued for %s (task: %s)\n", sendTo, resp.TaskID)
147→		} else {
148→			fmt.Printf("  \033[32m✓\033[0m Sent to %s (message ID: %s)\n", sendTo, resp.MessageID)
149→		}
