  path: "/api/validate-token",
  method: "POST",
  handler: validateToken,
});

http.route({
  path: "/api/revoke-token",
  method: "POST",
  handler: revokeToken,
});

// ── Unipile ──────────────────────────────────────────────────────────

http.route({
  path: "/api/unipile-webhook",
  method: "POST",
  handler: unipileWebhook,
});

http.route({
  path: "/api/unipile-account-callback",
  method: "POST",
  handler: unipileAccountCallback,
});

// ── CLI API ──────────────────────────────────────────────────────────

http.route({
  path: "/api/send-email",
  method: "POST",
  handler: sendEmail,
});

export default http;

