package connector

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"strings"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
)

// GenericConnector implements Connector backed by a YAMLConnector definition.
type GenericConnector struct {
	def         *YAMLConnector
	credentials string // optional override path (e.g. --credentials flag)
}

// saveToken writes an OAuth2 token to disk with restricted permissions.
func saveToken(path string, token *oauth2.Token) error {
	f, err := os.OpenFile(path, os.O_RDWR|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return err
	}
	defer f.Close()
	return json.NewEncoder(f).Encode(token)
}

func (g *GenericConnector) ID() string   { return g.def.ID }
func (g *GenericConnector) Name() string { return g.def.Name }
func (g *GenericConnector) Type() string { return g.def.Type }

func (g *GenericConnector) Connect(ctx context.Context) (*Result, error) {
	switch g.def.Auth.Method {
	case "oauth2":
		return g.connectOAuth2(ctx)
	case "api_key":
		return g.connectAPIKey(ctx)
	case "basic":
		return g.connectBasic(ctx)
	case "webhook":
		return g.connectWebhook(ctx)
	default:
		return nil, fmt.Errorf("unsupported auth method: %s", g.def.Auth.Method)
	}
}

func (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
	var oauthCfg *oauth2.Config
	var authOpts []oauth2.AuthCodeOption

	if g.def.Credentials.Source == "google_json" {
		// Google-specific: use google.ConfigFromJSON
		credsData, err := g.loadGoogleCredentials()
		if err != nil {
			return nil, err
		}
		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
		if err != nil {
			return nil, fmt.Errorf("parsing Google credentials: %w", err)
		}
		oauthCfg = cfg
	} else {
		// Generic OAuth2: build config from YAML
		clientID, clientSecret, err := g.resolveOAuthCredentials()
		if err != nil {
			return nil, err
		}
		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
		if err != nil {
			return nil, err
		}
		oauthCfg = cfg
		authOpts = opts
	}

	// Add extra_params as auth options for google_json too
	if g.def.Credentials.Source == "google_json" {
		for k, v := range g.def.Auth.ExtraParams {
			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
		}
	}

	// Run shared OAuth flow
	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
	if err != nil {
		return nil, err
	}

	// Save token
	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	tokenPath := tokenDir + "/token.json"
	if err := os.MkdirAll(tokenDir, 0755); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	if err := saveToken(tokenPath, token); err != nil {
		return nil, fmt.Errorf("saving token: %w", err)
	}

	// Verify connection + get account identifier
	account, err := g.runVerify(ctx, oauthCfg, token)
	if err != nil {
		// Non-fatal: connected but can't verify
		account = "connected (unverified)"
	}

	return &Result{
		Account: account,
		Token:   token,
	}, nil
}

func (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
	key := os.Getenv(g.def.Auth.EnvVar)
	if key == "" {
		// Check if stdin is a TTY for prompt
		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
			fmt.Printf("Enter your %s API key: ", g.def.Name)
			fmt.Scanln(&key)
		}
		if key == "" {
			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
		}
	}

	// Save API key
	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0755); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsPath := tokenDir + "/credentials.json"
	credsData, _ := json.Marshal(map[string]string{"api_key": key})
	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	// Verify
	account, err := g.runVerifyAPIKey(ctx, key)
	if err != nil {
		account = "connected (unverified)"
	}

	return &Result{
		Account: account,
		Meta:    map[string]string{"api_key": key},
	}, nil
}

func (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
	username := os.Getenv(g.def.Auth.UsernameVar)
	password := os.Getenv(g.def.Auth.PasswordVar)
	if username == "" || password == "" {
		return nil, fmt.Errorf("%s credentials not found. Set %s and %s environment variables",
			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
	}

	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0755); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	return &Result{Account: username}, nil
}

func (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
	webhookURL := os.Getenv(g.def.Auth.URLVar)
	if webhookURL == "" {
		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
			fmt.Scanln(&webhookURL)
		}
		if webhookURL == "" {
			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
				g.def.Name, g.def.Auth.URLVar)
		}
	}

	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
	if err := os.MkdirAll(tokenDir, 0755); err != nil {
		return nil, fmt.Errorf("creating connector dir: %w", err)
	}
	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
		return nil, fmt.Errorf("saving credentials: %w", err)
	}

	return &Result{Account: webhookURL}, nil
}

// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
func (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
	cfg := &oauth2.Config{
		ClientID:     clientID,
		ClientSecret: clientSecret,
		Scopes:       g.def.Auth.Scopes,
		Endpoint: oauth2.Endpoint{
			AuthURL:  g.def.Auth.AuthorizeURL,
			TokenURL: g.def.Auth.TokenURL,
		},
	}

	// Auth style
	switch g.def.Auth.AuthStyle {
	case "in_params":
		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
	case "in_header":
		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
	}

	// Extra params become AuthCodeOptions
	var opts []oauth2.AuthCodeOption
	for k, v := range g.def.Auth.ExtraParams {
		opts = append(opts, oauth2.SetAuthURLParam(k, v))
	}

	return cfg, opts, nil
}

// resolveOAuthCredentials reads client ID and secret from the configured source.
func (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
	cred := g.def.Credentials

	switch cred.Source {
	case "env":
		id := os.Getenv(cred.ClientIDVar)
		secret := os.Getenv(cred.ClientSecretVar)
		if id == "" || secret == "" {
			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
		}
		return id, secret, nil

	case "prompt":
		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
		}
		var id, secret string
		fmt.Printf("Enter %s client ID: ", g.def.Name)
		fmt.Scanln(&id)
		fmt.Printf("Enter %s client secret: ", g.def.Name)
		fmt.Scanln(&secret)
		if id == "" || secret == "" {
			return "", "", fmt.Errorf("client ID and secret are required")
		}
		return id, secret, nil

	default:
		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
	}
}

// loadGoogleCredentials loads credentials for google_json source (fallback chain).
func (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
	// 1. Explicit path from --credentials flag
	if g.credentials != "" {
		data, err := os.ReadFile(g.credentials)
		if err != nil {
			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
		}
		return data, nil
	}

	// 2. Local file in project
	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
	if data, err := os.ReadFile(localPath); err == nil {
		return data, nil
	}

	// 3. Bundled credentials
	if len(BundledCredentials) > 0 {
		return BundledCredentials, nil
	}

	return nil, fmt.Errorf("no %s credentials found — provide a credentials.json file", g.def.Name)
}

// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
func (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
	if g.def.Verify.URL == "" {
		return "connected", nil
	}

	// Refresh token first so URL substitution uses a valid access token
	ts := cfg.TokenSource(ctx, token)
	freshToken, err := ts.Token()
	if err != nil {
		freshToken = token // fall back to original if refresh fails
	}
	client := oauth2.NewClient(ctx, ts)
	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)

	method := g.def.Verify.Method
	if method == "" {
		method = "GET"
	}

	req, err := http.NewRequestWithContext(ctx, method, url, nil)
	if err != nil {
		return "", err
	}
	for k, v := range g.def.Verify.Headers {
		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
		req.Header.Set(k, v)
	}

	resp, err := client.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
	}

	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
}

// runVerifyAPIKey calls verify with an API key in the configured header.
func (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
	if g.def.Verify.URL == "" {
		return "connected", nil
	}

	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
	method := g.def.Verify.Method
	if method == "" {
		method = "GET"
	}

	req, err := http.NewRequestWithContext(ctx, method, url, nil)
	if err != nil {
		return "", err
	}

	if g.def.Auth.Header != "" {
		req.Header.Set(g.def.Auth.Header, key)
	}

	resp, err := http.DefaultClient.Do(req)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return "", fmt.Errorf("verify returned %d", resp.StatusCode)
	}

	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
}

// extractAccountField reads the JSON response and tries fields in preference order.
func extractAccountField(body io.Reader, fields []string) (string, error) {
	if len(fields) == 0 {
		return "connected", nil
	}

	var data map[string]interface{}
	if err := json.NewDecoder(body).Decode(&data); err != nil {
		return "", fmt.Errorf("parsing verify response: %w", err)
	}

	for _, field := range fields {
		if v, ok := data[field]; ok && v != nil {
			return fmt.Sprintf("%v", v), nil
		}
	}

	return "connected", nil
}

