package account

import (
	"context"
	_ "embed"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"strings"

	"golang.org/x/oauth2"
	"golang.org/x/oauth2/google"
)

//go:embed google_credentials.json
var googleCredentialsJSON []byte

var googleScopes = []string{
	"openid",
	"https://www.googleapis.com/auth/userinfo.email",
	"https://www.googleapis.com/auth/userinfo.profile",
}

// googleOAuthConfig builds an oauth2.Config from the embedded credentials.
// The redirect URI is set to http://localhost:<port> at call time.
func googleOAuthConfig(port int) (*oauth2.Config, error) {
	cfg, err := google.ConfigFromJSON(googleCredentialsJSON, googleScopes...)
	if err != nil {
		return nil, fmt.Errorf("parsing google credentials: %w", err)
	}
	cfg.RedirectURL = fmt.Sprintf("http://localhost:%d/callback", port)
	return cfg, nil
}

// GoogleOAuthResult holds the tokens from a successful Google OAuth flow.
type GoogleOAuthResult struct {
	IDToken      string
	RefreshToken string
}

// GetGoogleAuthURL returns the Google OAuth consent URL.
func GetGoogleAuthURL(port int, state string) (string, error) {
	cfg, err := googleOAuthConfig(port)
	if err != nil {
		return "", err
	}

	return cfg.AuthCodeURL(state,
		oauth2.AccessTypeOffline,
		oauth2.SetAuthURLParam("prompt", "select_account"),
	), nil
}

// ExchangeGoogleCode exchanges an authorization code for tokens.
// Returns the ID token and refresh token.
func ExchangeGoogleCode(ctx context.Context, port int, code string) (*GoogleOAuthResult, error) {
	cfg, err := googleOAuthConfig(port)
	if err != nil {
		return nil, err
	}

	token, err := cfg.Exchange(ctx, code)
	if err != nil {
		return nil, fmt.Errorf("exchanging code: %w", err)
	}

	// Extract ID token from the extra fields
	idToken, ok := token.Extra("id_token").(string)
	if !ok || idToken == "" {
		return nil, fmt.Errorf("no id_token in Google response")
	}

	return &GoogleOAuthResult{
		IDToken:      idToken,
		RefreshToken: token.RefreshToken,
	}, nil
}

// RefreshIDToken uses a stored refresh token to get a fresh ID token
// without opening the browser.
func RefreshIDToken(ctx context.Context, refreshToken string) (string, error) {
	cfg, err := googleOAuthConfig(0) // port doesn't matter for refresh
	if err != nil {
		return "", err
	}

	token := &oauth2.Token{RefreshToken: refreshToken}
	src := cfg.TokenSource(ctx, token)

	newToken, err := src.Token()
	if err != nil {
		return "", fmt.Errorf("refreshing token: %w", err)
	}

	idToken, ok := newToken.Extra("id_token").(string)
	if !ok || idToken == "" {
		return "", fmt.Errorf("no id_token in refresh response")
	}

	return idToken, nil
}

// GoogleUserInfo extracts basic user info from the ID token payload.
// Local JWT decode (no network call) — only for display purposes.
func GoogleUserInfo(idToken string) (email, name string, err error) {
	parts := strings.SplitN(idToken, ".", 3)
	if len(parts) != 3 {
		return "", "", fmt.Errorf("invalid id_token format")
	}

	payload, err := base64.RawURLEncoding.DecodeString(parts[1])
	if err != nil {
		return "", "", fmt.Errorf("decoding id_token payload: %w", err)
	}

	var claims struct {
		Email string `json:"email"`
		Name  string `json:"name"`
	}
	if err := json.Unmarshal(payload, &claims); err != nil {
		return "", "", fmt.Errorf("parsing id_token claims: %w", err)
	}

	return claims.Email, claims.Name, nil
}

