// AuthFile represents the local auth credentials stored at ~/.nurge/auth.json.
type AuthFile struct {
	Token             string `json:"token"`
	Email             string `json:"email"`
	Name              string `json:"name"`
	GoogleRefreshToken string `json:"google_refresh_token,omitempty"`
	CreatedAt         string `json:"created_at,omitempty"`
	ValidatedAt       string `json:"validated_at,omitempty"`
}

func authDir() (string, error) {
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("getting home directory: %w", err)
	}
	return filepath.Join(home, ".nurge"), nil
}

func authFilePath() (string, error) {
	dir, err := authDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(dir, "auth.json"), nil
}

// LoadAuth reads the auth file from ~/.nurge/auth.json.
func LoadAuth() (*AuthFile, error) {
	path, err := authFilePath()
	if err != nil {
		return nil, err
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("reading auth file: %w", err)
	}
	var af AuthFile
	if err := json.Unmarshal(data, &af); err != nil {
		return nil, fmt.Errorf("parsing auth file: %w", err)
	}
	return &af, nil
}

// SaveAuth writes the auth file to ~/.nurge/auth.json.
// Creates ~/.nurge/ with 0700 if it doesn't exist.
// Writes auth.json with 0600 permissions.
func SaveAuth(af *AuthFile) error {
	dir, err := authDir()
	if err != nil {
		return err
	}
	if err := os.MkdirAll(dir, 0700); err != nil {
		return fmt.Errorf("creating auth directory: %w", err)
	}

	data, err := json.MarshalIndent(af, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling auth file: %w", err)
	}

	path := filepath.Join(dir, "auth.json")
	if err := os.WriteFile(path, data, 0600); err != nil {
		return fmt.Errorf("writing auth file: %w", err)
	}
	return nil
}

// DeleteAuth removes ~/.nurge/auth.json.
func DeleteAuth() error {
	path, err := authFilePath()
	if err != nil {
		return err
	}
	if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
		return fmt.Errorf("deleting auth file: %w", err)
	}
	return nil
}

