// Append to internal/account/convex.go

// ConnectGmailResponse is returned by /api/connect-gmail.
type ConnectGmailResponse struct {
	URL              string `json:"url,omitempty"`
	AlreadyConnected bool   `json:"already_connected,omitempty"`
	Email            string `json:"email,omitempty"`
	Error            string `json:"error,omitempty"`
}

// ConnectGmail requests a Unipile hosted auth link from Convex.
func (c *ConvexClient) ConnectGmail(token string) (*ConnectGmailResponse, error) {
	httpReq, err := http.NewRequest("POST", c.baseURL+"/api/connect-gmail", nil)
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling connect-gmail: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result ConnectGmailResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}
	if result.Error != "" {
		return nil, fmt.Errorf("%s", result.Error)
	}
	return &result, nil
}

// ConnectionStatusResponse is returned by /api/connection-status.
type ConnectionStatusResponse struct {
	Connected bool   `json:"connected"`
	Email     string `json:"email,omitempty"`
	Status    string `json:"status,omitempty"`
	Error     string `json:"error,omitempty"`
}

// ConnectionStatus checks if the user's Gmail is connected via Unipile.
func (c *ConvexClient) ConnectionStatus(token string) (*ConnectionStatusResponse, error) {
	httpReq, err := http.NewRequest("GET", c.baseURL+"/api/connection-status", nil)
	if err != nil {
		return nil, fmt.Errorf("creating request: %w", err)
	}
	httpReq.Header.Set("Authorization", "Bearer "+token)

	resp, err := c.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("calling connection-status: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	var result ConnectionStatusResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing response: %w", err)
	}
	return &result, nil
}
```

- [ ] **Step 2: Rewrite `cmd/connect.go` to use Convex→Unipile flow**

Replace the entire connect command:

```go
package cmd

import (
	"fmt"
	"os"
	"time"

	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/project"
	"github.com/usenurge/nurgesh/internal/util"
	"github.com/spf13/cobra"
)

var connectCmd = &cobra.Command{
	Use:   "connect <service>",
	Short: "Connect a service (gmail)",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]

		switch id {
		case "gmail":
			return connectGmail()
		default:
			fmt.Printf("Unknown service: %s\n", id)
			fmt.Println("Available: gmail")
			return fmt.Errorf("unknown service: %s", id)
		}
	},
}

func connectGmail() error {
	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return fmt.Errorf("not logged in. Run: nurge account login")
	}

	client := account.NewConvexClient(GetConvexURL())

	// Request Unipile hosted auth link
	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
	resp, err := client.ConnectGmail(af.Token)
	if err != nil {
		return fmt.Errorf("connect failed: %w", err)
	}

	if resp.AlreadyConnected {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Gmail already connected (%s)\n", resp.Email)

		if project.IsNurgeProject(".") {
			_ = project.SetConnector("gmail", "email", resp.Email)
		}
		return nil
	}

	// Open Unipile hosted auth in browser
	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
	if err := util.OpenBrowser(resp.URL); err != nil {
		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
	}

	// Poll for completion
	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
	timeout := time.After(5 * time.Minute)
	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-timeout:
			fmt.Fprintf(os.Stderr, "\n")
			return fmt.Errorf("timed out waiting for Gmail connection")
		case <-ticker.C:
			status, err := client.ConnectionStatus(af.Token)
			if err != nil {
				continue // retry on transient errors
			}
