	ToEmails    string `json:"toEmails"`
	CcEmails    string `json:"ccEmails"`
	Date        string `json:"date"`
	Snippet     string `json:"snippet"`
}

// StoreConvexEmails stores emails fetched from Convex into the local SQLite DB.
func StoreConvexEmails(d *sql.DB, emails []ConvexEmail) (*SyncResult, error) {
	start := time.Now()
	result := &SyncResult{Fetched: len(emails)}

	for _, ce := range emails {
		raw := &RawMessage{
			ID:        ce.ExternalID,
			Source:    ce.Source,
			Direction: ce.Direction,
			ThreadID:  ce.ThreadID,
			Subject:   ce.Subject,
			FromEmail: ce.FromEmail,
			ToEmails:  ce.ToEmails,
			CcEmails:  ce.CcEmails,
			Date:      ce.Date,
			Snippet:   ce.Snippet,
		}
		if err := StoreEmail(d, raw); err != nil {
			fmt.Printf("  warning: storing email %s: %v\n", ce.ExternalID, err)
			continue
		}
		result.Stored++
	}

	result.Cursor = time.Now().UTC().Format(time.RFC3339)
	result.Duration = time.Since(start)

	// Update connector sync cursor
	d.Exec(
		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
		 VALUES ('gmail', 'email', ?, ?, ?)
		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
		result.Cursor, result.Cursor, result.Stored,
		result.Cursor, result.Cursor, result.Stored,
	)

	return result, nil
}
