		if err != nil {
			return fmt.Errorf("opening database: %w", err)
		}
		defer d.Close()

		af, err := account.LoadAuth()
		if err != nil || af.Token == "" {
			return fmt.Errorf("not logged in. Run: nurge account login")
		}

		client := account.NewConvexClient(GetConvexURL())

		// Get last sync version from local DB
		var lastVersion float64
		d.QueryRow("SELECT COALESCE(MAX(CAST(sync_cursor AS REAL)), 0) FROM connectors WHERE id = 'gmail'").Scan(&lastVersion)

		fmt.Println("  Syncing sent emails...")

		resp, err := client.SyncEmails(af.Token, lastVersion)
		if err != nil {
			return fmt.Errorf("sync failed: %w", err)
		}

		if resp.Count == 0 {
			fmt.Println("  ✓ Already up to date")
			return nil
		}

		// Convert account.ConvexEmail to email.ConvexEmail
		convexEmails := make([]email.ConvexEmail, len(resp.Emails))
		for i, e := range resp.Emails {
			convexEmails[i] = email.ConvexEmail{
				ExternalID: e.ExternalID,
				Source:     e.Source,
				Direction:  e.Direction,
				ThreadID:   e.ThreadID,
				Subject:    e.Subject,
				FromEmail:  e.FromEmail,
				ToEmails:   e.ToEmails,
				CcEmails:   e.CcEmails,
				Date:       e.Date,
				Snippet:    e.Snippet,
			}
		}

		result, err := email.StoreConvexEmails(d, convexEmails)
		if err != nil {
			return fmt.Errorf("storing emails: %w", err)
		}

		fmt.Printf("  ✓ Synced %d emails (%d fetched) in %s\n",
			result.Stored, result.Fetched, result.Duration.Round(time.Second))

		return nil
	},
}

