604→// StoreConvexEmails stores emails fetched from Convex into the local SQLite DB.
605→func StoreConvexEmails(d *sql.DB, emails []ConvexEmail) (*SyncResult, error) {
606→	start := time.Now()
607→	result := &SyncResult{Fetched: len(emails)}
608→
609→	for _, ce := range emails {
610→		raw := &RawMessage{
611→			ID:        ce.ExternalID,
612→			Source:    ce.Source,
613→			Direction: ce.Direction,
614→			ThreadID:  ce.ThreadID,
615→			Subject:   ce.Subject,
616→			FromEmail: ce.FromEmail,
617→			ToEmails:  ce.ToEmails,
618→			CcEmails:  ce.CcEmails,
619→			Date:      ce.Date,
620→			Snippet:   ce.Snippet,
621→		}
622→		if err := StoreEmail(d, raw); err != nil {
623→			fmt.Printf("  warning: storing email %s: %v\n", ce.ExternalID, err)
624→			continue
625→		}
626→		result.Stored++
627→	}
628→
629→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
630→	result.Duration = time.Since(start)
631→
632→	// Update connector sync cursor
633→	d.Exec(
634→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
635→		 VALUES ('gmail', 'email', ?, ?, ?)
636→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
637→		result.Cursor, result.Cursor, result.Stored,
638→		result.Cursor, result.Cursor, result.Stored,
639→	)
640→
641→	return result, nil
642→}
