 95→      reply: mailbox.replyDailyCap,
 96→    };
 97→    const cap = capMap[effectiveSendType] || 0;
 98→    if (cap > 0 && sendCount >= cap) {
 99→      if (sync) {
100→        return jsonResponse({ ok: false, error: `Daily ${effectiveSendType} cap reached (${cap})` }, 400);
101→      }
102→    }
103→
104→    // --- Generate IDs ---
105→    const now = new Date().toISOString();
106→    const taskExternalId = `task-${Date.now()}-${randomSuffix()}`;
107→    const enrollmentExternalId = sequence ? `enr-${Date.now()}-${randomSuffix()}` : "";
108→
109→    // --- Create enrollment + future tasks if sequence ---
110→    if (sequence) {
111→      // Check for existing active enrollment
112→      const existingEnrollment = await ctx.runQuery(internal.sendApi.findActiveEnrollment, {
113→        userId,
114→        mailboxId: mailbox.externalId,
115→        contactEmail: to,
116→      });
117→      if (existingEnrollment) {
118→        return jsonResponse({
119→          ok: false,
120→          error: `${to} already has an active sequence enrollment (${existingEnrollment.externalId})`,
121→        }, 400);
122→      }
123→
124→      await ctx.runMutation(internal.sendApi.createSendEnrollment, {
125→        userId,
126→        enrollment: {
127→          externalId: enrollmentExternalId,
128→          sequenceName: sequence.sequenceName,
129→          campaignName: sequence.campaignName || "",
130→          mailboxId: mailbox.externalId,
131→          contactEmail: to,
132→          contactName: sequence.contactName || "",
133→          subject,
134→          currentStep: 1,
135→          totalSteps: 1 + (sequence.steps?.length || 0),
136→          initialBody: body,
137→          unipileAccountId: unipileAccount.unipileAccountId,
138→        },
139→        firstTask: {
140→          externalId: taskExternalId,
141→          stepNumber: 1,
142→          stepName: "first_touch",
143→          sendType: "first_touch",
144→          dueAt: now,
145→          subject,
146→          body,
147→          contactEmail: to,
148→          mailboxId: mailbox.externalId,
149→        },
150→        futureSteps: (sequence.steps || []).map((step: any, i: number) => {
151→          const stepTaskId = `task-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
152→          const draftId = `draft-${Date.now()}-${randomSuffix()}-s${step.stepNumber || i + 2}`;
153→          const dueDate = new Date(Date.now() + (step.delayDays || 3) * 86400000).toISOString();
154→          return {
155→            task: {
156→              externalId: stepTaskId,
157→              stepNumber: step.stepNumber || i + 2,
158→              stepName: step.stepName || `follow_up_${i + 1}`,
159→              sendType: step.sendType || "follow_up",
160→              dueAt: dueDate,
161→              subject: step.subject || subject,
162→              body: step.body || "",
163→              contactEmail: to,
164→              mailboxId: mailbox.externalId,
165→            },
166→            draft: {
167→              externalId: draftId,
168→              taskId: stepTaskId,
169→              stepNumber: step.stepNumber || i + 2,
170→              subject: step.subject || subject,
171→              body: step.body || "",
172→              channel: "email",
173→            },
174→          };
175→        }),
176→      });
177→    } else {
178→      // One-off send: create standalone task
179→      await ctx.runMutation(internal.sendApi.createStandaloneTask, {
180→        userId,
181→        task: {
182→          externalId: taskExternalId,
183→          enrollmentId: "",
184→          mailboxId: mailbox.externalId,
185→          contactEmail: to,
186→          subject,
187→          body,
188→          stepNumber: 1,
189→          sendType: effectiveSendType,
190→          dueAt: now,
191→        },
192→      });
193→    }
194→
195→    // --- Sync: send now ---
196→    if (sync) {
197→      const sendResult = await callUnipileSend({
198→        accountId: unipileAccount.unipileAccountId,
199→        to,
200→        subject,
201→        body,
202→      });
203→
204→      if (!sendResult.ok) {
205→        await ctx.runMutation(internal.sendApi.markTaskFailed, {
206→          userId,
207→          taskId: taskExternalId,
208→          error: sendResult.error,
209→          authError: sendResult.authError,
210→          mailboxId: mailbox.externalId,
211→        });
212→        return jsonResponse({ ok: false, error: sendResult.error }, 502);
213→      }
214→
215→      await ctx.runMutation(internal.sendApi.markTaskSent, {
216→        userId,
217→        taskId: taskExternalId,
218→        enrollmentId: enrollmentExternalId,
219→        mailboxId: mailbox.externalId,
220→        sendType: effectiveSendType,
221→        unipileMessageId: sendResult.messageId,
222→        providerId: sendResult.providerId,
223→      });
224→
225→      return jsonResponse({
226→        ok: true,
227→        messageId: sendResult.messageId,
228→        providerId: sendResult.providerId,
229→        taskId: taskExternalId,
230→        enrollmentId: enrollmentExternalId || undefined,
231→      });
232→    }
233→
234→    // --- Async: return queued ---
235→    return jsonResponse({
236→      ok: true,
237→      queued: true,
238→      taskId: taskExternalId,
239→      enrollmentId: enrollmentExternalId || undefined,
240→    });
241→  } catch (error: any) {
242→    console.error("sendEmail error:", error);
243→    return jsonResponse({ ok: false, error: error.message || "Internal error" }, 500);
244→  }
245→});
