247→// Handle sending an existing task (--task-id flow)
248→async function handleExistingTask(ctx: any, userId: string, taskId: string, payload: any) {
249→  const task = await ctx.runQuery(internal.sendApi.findTask, { externalId: taskId });
250→  if (!task) {
251→    return jsonResponse({ ok: false, error: `Task ${taskId} not found` }, 404);
252→  }
253→  if (task.userId !== userId) {
254→    return jsonResponse({ ok: false, error: "Task does not belong to this user" }, 403);
255→  }
256→  if (task.status !== "open") {
257→    return jsonResponse({ ok: false, error: `Task is ${task.status}, not open` }, 400);
258→  }
259→  if (task.sendStatus === "sent") {
260→    return jsonResponse({ ok: false, error: "Task already sent" }, 400);
261→  }
262→
263→  // Resolve Unipile account
264→  const unipileAccount = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
265→    userId,
266→    provider: "GOOGLE",
267→  });
268→  if (!unipileAccount) {
269→    return jsonResponse({ ok: false, error: "No connected email account" }, 400);
270→  }
271→
272→  // Use payload overrides or task defaults
273→  const to = payload.to || task.contactEmail;
274→  const subject = payload.subject || task.subject || "";
275→  const body = payload.body || task.body || "";
276→
277→  // Look up draft for latest content
278→  const draft = await ctx.runQuery(internal.sendApi.findDraft, { taskId });
279→  const finalSubject = subject || draft?.subject || "";
280→  const finalBody = body || draft?.body || "";
281→
282→  if (!finalSubject || !finalBody) {
283→    return jsonResponse({ ok: false, error: "No subject or body available for this task" }, 400);
284→  }
285→
286→  // Get enrollment for threading
287→  const enrollment = task.enrollmentId
288→    ? await ctx.runQuery(internal.sendApi.findEnrollment, { externalId: task.enrollmentId })
289→    : null;
290→
291→  const replyTo = enrollment?.unipileThreadProviderId || undefined;
292→
293→  const sendResult = await callUnipileSend({
294→    accountId: unipileAccount.unipileAccountId,
295→    to,
296→    subject: finalSubject,
297→    body: finalBody,
298→    replyTo,
299→  });
300→
301→  if (!sendResult.ok) {
302→    await ctx.runMutation(internal.sendApi.markTaskFailed, {
303→      userId,
304→      taskId,
305→      error: sendResult.error,
306→      authError: sendResult.authError,
307→      mailboxId: task.mailboxId,
308→    });
309→    return jsonResponse({ ok: false, error: sendResult.error }, 502);
310→  }
311→
312→  await ctx.runMutation(internal.sendApi.markTaskSent, {
313→    userId,
314→    taskId,
315→    enrollmentId: task.enrollmentId,
316→    mailboxId: task.mailboxId,
317→    sendType: task.sendType,
318→    unipileMessageId: sendResult.messageId,
319→    providerId: sendResult.providerId,
320→  });
321→
322→  return jsonResponse({
323→    ok: true,
324→    messageId: sendResult.messageId,
325→    providerId: sendResult.providerId,
326→    taskId,
327→    enrollmentId: task.enrollmentId || undefined,
328→  });
329→}
