628→export const markTaskSent = internalMutation({
629→  args: {
630→    userId: v.string(),
631→    taskId: v.string(),
632→    enrollmentId: v.string(),
633→    mailboxId: v.string(),
634→    sendType: v.string(),
635→    unipileMessageId: v.string(),
636→    providerId: v.string(),
637→  },
638→  handler: async (ctx, args) => {
639→    const task = await ctx.db
640→      .query("followUpTasks")
641→      .withIndex("by_external_id", (q) => q.eq("externalId", args.taskId))
642→      .first();
643→    if (!task) return;
644→
645→    const syncState = await ctx.db
646→      .query("syncState")
647→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
648→      .first();
649→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
650→
651→    // Update task
652→    await ctx.db.patch(task._id, {
653→      status: "completed",
654→      sendStatus: "sent",
655→      completedAt: new Date().toISOString(),
656→      unipileMessageId: args.unipileMessageId,
657→      providerId: args.providerId,
658→      syncVersion: version,
659→    });
660→
661→    // Create send event
662→    const sendEventId = `mse-${Date.now()}-${randomSuffix()}`;
663→    await ctx.db.insert("mailboxSendEvents", {
664→      externalId: sendEventId,
665→      mailboxId: args.mailboxId,
666→      sendType: args.sendType,
667→      sentAt: new Date().toISOString(),
668→      taskId: args.taskId,
669→      enrollmentId: args.enrollmentId,
670→      unipileMessageId: args.unipileMessageId,
671→      providerId: args.providerId,
672→      syncVersion: version,
673→      userId: args.userId,
674→    });
675→
676→    // Advance enrollment if applicable
677→    if (args.enrollmentId) {
678→      const enrollment = await ctx.db
679→        .query("sequenceEnrollments")
680→        .withIndex("by_external_id", (q) => q.eq("externalId", args.enrollmentId))
681→        .first();
682→
683→      if (enrollment) {
684→        version++;
685→        const newStep = task.stepNumber;
686→        const isComplete = newStep >= enrollment.totalSteps;
687→
688→        await ctx.db.patch(enrollment._id, {
689→          currentStep: newStep,
690→          lastSentAt: new Date().toISOString(),
691→          lastMessageId: args.unipileMessageId,
692→          status: isComplete ? "completed" : enrollment.status,
693→          nextDueAt: isComplete ? "" : enrollment.nextDueAt,
694→          unipileThreadProviderId: args.providerId || enrollment.unipileThreadProviderId,
695→          syncVersion: version,
696→        });
697→
698→        // Mark draft as sent
699→        const draft = await ctx.db
700→          .query("sequenceDrafts")
701→          .withIndex("by_task", (q) => q.eq("taskId", args.taskId))
702→          .first();
703→        if (draft) {
704→          await ctx.db.patch(draft._id, {
705→            status: "sent",
706→            syncVersion: version,
707→          });
708→        }
709→      }
710→    }
711→
712→    if (syncState) {
713→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
714→    } else {
715→      await ctx.db.insert("syncState", { userId: args.userId, lastSyncVersion: version });
716→    }
717→  },
718→});
