751→    // Mark mailbox auth_expired on auth errors
752→    if (args.authError && args.mailboxId) {
753→      const mailbox = await ctx.db
754→        .query("mailboxes")
755→        .withIndex("by_external_id", (q) => q.eq("externalId", args.mailboxId))
756→        .first();
757→      if (mailbox) {
758→        version++;
759→        await ctx.db.patch(mailbox._id, {
760→          status: "auth_expired",
761→          syncVersion: version,
762→        });
763→      }
764→    }
765→
766→    if (syncState) {
767→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
768→    } else {
