 48→async function handleNewEmail(ctx: any, payload: any) {
 49→  const email = payload.data || payload;
 50→  const providerId = email.provider_id
 51→    ? JSON.stringify(email.provider_id)
 52→    : "";
 53→  const accountId = email.account_id || "";
 54→  const from = email.from?.identifier || email.from_email || "";
 55→  const threadId = email.thread_id || "";
 56→
 57→  // Find the Unipile account to get the userId
 58→  const account = accountId
 59→    ? await ctx.runQuery(internal.webhook.findAccountByUnipileId, {
 60→        unipileAccountId: accountId,
 61→      })
 62→    : null;
 63→
 64→  if (!account) {
 65→    console.log("No matching Unipile account for:", accountId);
 66→    return;
 67→  }
 68→
 69→  // Check if this email is on a thread with an active enrollment
 70→  if (threadId || providerId) {
 71→    await ctx.runMutation(internal.webhook.processReply, {
 72→      userId: account.userId,
 73→      fromEmail: from,
 74→      threadId,
 75→      providerId,
 76→      messageId: email.id || "",
 77→      subject: email.subject || "",
 78→      snippet: email.body_plain?.substring(0, 200) || "",
 79→    });
 80→  }
 81→}
 82→
 83→async function handleAccountStatus(ctx: any, payload: any) {
 84→  const data = payload.data || payload;
 85→  const accountId = data.account_id || "";
 86→  const status = data.status || "";
 87→
 88→  if (status === "disconnected" || status === "error") {
 89→    const account = await ctx.runQuery(
 90→      internal.webhook.findAccountByUnipileId,
 91→      { unipileAccountId: accountId }
 92→    );
 93→
 94→    if (account) {
 95→      await ctx.runMutation(internal.webhook.markMailboxAuthExpired, {
 96→        userId: account.userId,
 97→        unipileAccountId: accountId,
 98→      });
 99→    }
100→  }
101→}
