143→export const processReply = internalMutation({
144→  args: {
145→    userId: v.string(),
146→    fromEmail: v.string(),
147→    threadId: v.string(),
148→    providerId: v.string(),
149→    messageId: v.string(),
150→    subject: v.optional(v.string()),
151→    snippet: v.optional(v.string()),
152→  },
153→  handler: async (ctx, args) => {
154→    // Find active enrollments for this contact
155→    const enrollments = await ctx.db
156→      .query("sequenceEnrollments")
157→      .withIndex("by_contact", (q) =>
158→        q.eq("userId", args.userId).eq("contactEmail", args.fromEmail)
159→      )
160→      .collect();
161→
162→    const activeEnrollments = enrollments.filter(
163→      (e) => e.status === "active" || e.status === "paused"
164→    );
165→
166→    if (activeEnrollments.length === 0) return;
167→
168→    // Get sync version
169→    const syncState = await ctx.db
170→      .query("syncState")
171→      .withIndex("by_user", (q) => q.eq("userId", args.userId))
172→      .first();
173→    let version = (syncState?.lastSyncVersion ?? 0) + 1;
174→
175→    // Stop ALL active enrollments for this contact
176→    for (const enrollment of activeEnrollments) {
177→      await ctx.db.patch(enrollment._id, {
178→        status: "stopped",
179→        statusReason: "reply received",
180→        replyState: "needs_classification",
181→        lastReplyAt: new Date().toISOString(),
182→        nextDueAt: "",
183→        syncVersion: version,
184→      });
185→
186→      // Cancel all pending tasks
187→      const tasks = await ctx.db
188→        .query("followUpTasks")
189→        .withIndex("by_enrollment", (q) =>
190→          q.eq("enrollmentId", enrollment.externalId)
191→        )
192→        .collect();
193→
194→      for (const task of tasks) {
195→        if (task.status === "open") {
196→          await ctx.db.patch(task._id, {
197→            status: "canceled",
198→            sendStatus: "canceled",
199→            canceledReason: "reply received",
200→            syncVersion: version,
201→          });
202→        }
203→      }
204→
205→      // Cancel pending drafts
206→      const drafts = await ctx.db
207→        .query("sequenceDrafts")
208→        .withIndex("by_enrollment", (q) =>
209→          q.eq("enrollmentId", enrollment.externalId)
210→        )
211→        .collect();
212→
213→      for (const draft of drafts) {
214→        if (draft.status === "pending") {
215→          await ctx.db.patch(draft._id, {
216→            status: "canceled",
217→            syncVersion: version,
218→          });
219→        }
220→      }
221→
222→      // Record reply event
223→      const replyId = `re-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
224→      await ctx.db.insert("replyEvents", {
225→        externalId: replyId,
226→        enrollmentId: enrollment.externalId,
227→        mailboxId: enrollment.mailboxId,
228→        threadId: args.threadId,
229→        messageId: args.messageId,
230→        contactEmail: args.fromEmail,
231→        classification: "needs_classification",
232→        subject: args.subject,
233→        snippet: args.snippet,
234→        occurredAt: new Date().toISOString(),
235→        syncVersion: version,
236→        userId: args.userId,
237→      });
238→
239→      version++;
240→    }
241→
242→    // Update sync state
243→    if (syncState) {
244→      await ctx.db.patch(syncState._id, { lastSyncVersion: version });
245→    } else {
246→      await ctx.db.insert("syncState", {
247→        userId: args.userId,
248→        lastSyncVersion: version,
249→      });
250→    }
251→  },
252→});
