 68→// POST /api/connect-gmail — returns Unipile hosted auth URL for Gmail
 69→export const connectGmail = httpAction(async (ctx, request) => {
 70→  try {
 71→    const auth = await authenticateRequest(ctx, request);
 72→    if (auth.error) return auth.error;
 73→    const user = auth.user!;
 74→
 75→    // Check if already connected
 76→    const existing = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
 77→      userId: user._id,
 78→      provider: "GOOGLE",
 79→    });
 80→    if (existing && existing.status === "connected") {
 81→      return jsonResponse({ already_connected: true, email: existing.email });
 82→    }
 83→
 84→    // Get Unipile hosted auth link
 85→    const result = await ctx.runAction(api.unipile.requestConnectionLink, {
 86→      userId: user._id,
 87→      provider: "GOOGLE",
 88→    });
 89→
 90→    return jsonResponse({ url: result.url });
 91→  } catch (error: any) {
 92→    console.error("connect-gmail error:", error);
 93→    return jsonResponse({ error: error.message }, 500);
 94→  }
 95→});
