 97→// GET /api/connection-status — CLI polls this after opening auth URL
 98→export const connectionStatus = httpAction(async (ctx, request) => {
 99→  try {
100→    const auth = await authenticateRequest(ctx, request);
101→    if (auth.error) return auth.error;
102→    const user = auth.user!;
103→
104→    const account = await ctx.runQuery(internal.sendApi.findUnipileAccount, {
105→      userId: user._id,
106→      provider: "GOOGLE",
107→    });
108→
109→    if (!account) {
110→      return jsonResponse({ connected: false });
111→    }
112→
113→    return jsonResponse({
114→      connected: account.status === "connected",
115→      email: account.email || "",
116→      status: account.status,
117→    });
118→  } catch (error: any) {
119→    return jsonResponse({ error: error.message }, 500);
120→  }
121→});
