123→// POST /api/sync-emails — CLI fetches emails from Convex (backfilled from Unipile)
124→export const syncEmails = httpAction(async (ctx, request) => {
125→  try {
126→    const auth = await authenticateRequest(ctx, request);
127→    if (auth.error) return auth.error;
128→    const user = auth.user!;
129→
130→    const payload = await request.json().catch(() => ({}));
131→    const afterVersion = payload.afterVersion ?? 0;
132→
133→    const emails = await ctx.runQuery(internal.connect.listEmailsAfterVersion, {
134→      userId: user._id,
135→      afterVersion,
136→    });
137→
138→    return jsonResponse({ emails, count: emails.length });
139→  } catch (error: any) {
140→    return jsonResponse({ error: error.message }, 500);
141→  }
142→});
143→
144→// --- Internal queries for sync-emails ---
145→
146→export const listEmailsAfterVersion = internalQuery({
147→  args: {
148→    userId: v.string(),
149→    afterVersion: v.float64(),
150→  },
151→  handler: async (ctx, args) => {
152→    // Use by_sync_version index for efficient filtering
153→    const allEmails = await ctx.db
154→      .query("emails")
155→      .withIndex("by_sync_version")
156→      .collect();
157→    // Filter by user and version (index gives us version ordering)
158→    return allEmails
159→      .filter(
160→        (e) =>
161→          e.userId === args.userId && e.syncVersion > args.afterVersion
162→      )
163→      .slice(0, 500);
164→  },
165→});
