503→// StoreConvexEmails stores emails fetched from Convex into local SQLite.
504→// Uses the same StoreEmail function as the Gmail API sync path.
505→func StoreConvexEmails(d *sql.DB, emails []RawMessage) (*SyncResult, error) {
506→	start := time.Now()
507→	result := &SyncResult{Fetched: len(emails)}
508→
509→	for _, e := range emails {
510→		raw := e // copy for pointer
511→		if err := StoreEmail(d, &raw); err != nil {
512→			fmt.Printf("  warning: storing email %s: %v\n", e.ID, err)
513→			continue
514→		}
515→		result.Stored++
516→	}
517→
518→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
519→	result.Duration = time.Since(start)
520→
521→	d.Exec(
522→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
523→		 VALUES ('gmail', 'email', ?, ?, ?)
524→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
525→		result.Cursor, result.Cursor, result.Stored,
526→		result.Cursor, result.Cursor, result.Stored,
527→	)
528→
529→	return result, nil
530→}
531→```
