```go
// Add to internal/email/sync.go, after StoreEmail function

// StoreConvexEmails stores emails fetched from Convex into local SQLite.
// Uses the same StoreEmail function as the Gmail API sync path.
func StoreConvexEmails(d *sql.DB, emails []RawMessage) (*SyncResult, error) {
	start := time.Now()
	result := &SyncResult{Fetched: len(emails)}

	for _, e := range emails {
		raw := e // copy for pointer
		if err := StoreEmail(d, &raw); err != nil {
			fmt.Printf("  warning: storing email %s: %v\n", e.ID, err)
			continue
		}
		result.Stored++
	}

	result.Cursor = time.Now().UTC().Format(time.RFC3339)
	result.Duration = time.Since(start)

	d.Exec(
		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
		 VALUES ('gmail', 'email', ?, ?, ?)
		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
		result.Cursor, result.Cursor, result.Stored,
		result.Cursor, result.Cursor, result.Stored,
	)

	return result, nil
}
```

Note: Uses `[]RawMessage` directly (no duplicate ConvexEmail type). The `cmd/sync.go` maps from `account.ConvexEmail` to `email.RawMessage`.

- [ ] **Step 2: Rewrite `cmd/sync.go`**

Track `last_sync_version` as a separate float column (or a dedicated row) to avoid the cursor type mismatch. The simplest fix: store the max syncVersion in `sync_cursor` as a float string.

```go
package cmd

import (
	"fmt"
	"strconv"
	"time"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/email"
)

var syncCmd = &cobra.Command{
	Use:   "sync",
	Short: "Sync emails from connected sources",
	Long:  "Fetches sent emails via Convex (last 90 days on first sync, incremental after).",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return fmt.Errorf("opening database: %w", err)
		}
		defer d.Close()

		af, err := account.LoadAuth()
		if err != nil || af.Token == "" {
			return fmt.Errorf("not logged in. Run: nurge account login")
		}

		client := account.NewConvexClient(GetConvexURL())

		// Read last sync version (stored as float string in a dedicated connector row)
		var lastVersionStr string
		d.QueryRow("SELECT COALESCE(sync_cursor, '0') FROM connectors WHERE id = 'gmail-convex'").Scan(&lastVersionStr)
		lastVersion, _ := strconv.ParseFloat(lastVersionStr, 64)

		fmt.Println("  Syncing sent emails...")

		resp, err := client.SyncEmails(af.Token, lastVersion)
		if err != nil {
			return fmt.Errorf("sync failed: %w", err)
		}

		if resp.Count == 0 {
			fmt.Println("  Already up to date")
			return nil
		}

		// Convert to RawMessage
		raws := make([]email.RawMessage, len(resp.Emails))
		var maxVersion float64
		for i, e := range resp.Emails {
			raws[i] = email.RawMessage{
				ID:        e.ExternalID,
				Source:     e.Source,
				Direction:  e.Direction,
				ThreadID:   e.ThreadID,
				Subject:    e.Subject,
				FromEmail:  e.FromEmail,
				ToEmails:   e.ToEmails,
				CcEmails:   e.CcEmails,
				Date:       e.Date,
				Snippet:    e.Snippet,
			}
			if e.SyncVersion > maxVersion {
				maxVersion = e.SyncVersion
			}
		}

		result, err := email.StoreConvexEmails(d, raws)
		if err != nil {
			return fmt.Errorf("storing emails: %w", err)
		}

		// Store the max sync version for next incremental sync
		d.Exec(
			`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
			 VALUES ('gmail-convex', 'email', ?, datetime('now'), ?)
			 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = datetime('now'), total_synced = total_synced + ?`,
			strconv.FormatFloat(maxVersion, 'f', -1, 64), result.Stored,
			strconv.FormatFloat(maxVersion, 'f', -1, 64), result.Stored,
		)

		fmt.Printf("  \033[32m✓\033[0m Synced %d emails (%d fetched) in %s\n",
			result.Stored, result.Fetched, result.Duration.Round(time.Second))

