import { v } from "convex/values";
import { httpAction, internalQuery, internalMutation } from "./_generated/server";
import { api, internal } from "./_generated/api";

// Unipile webhook receiver — handles new emails, tracking, account status
export const unipileWebhook = httpAction(async (ctx, request) => {
  // Verify Unipile-Auth shared secret
  const secret = process.env.UNIPILE_WEBHOOK_SECRET;
  const authHeader = request.headers.get("Unipile-Auth");

  if (secret && authHeader !== secret) {
    console.error("Webhook auth failed: invalid Unipile-Auth header");
    return new Response("Unauthorized", { status: 401 });
  }

  try {
    const payload = await request.json();
    const eventType = payload.event || payload.type;

    switch (eventType) {
      case "new_email":
      case "mail.received":
        await handleNewEmail(ctx, payload);
        break;

      case "email_tracking":
      case "mail.tracking":
        // Log open/click events — useful for analytics
        console.log("Email tracking event:", JSON.stringify(payload));
        break;

